import React, { useState, useEffect, useMemo } from 'react';
import { 
  Camera, 
  Menu, 
  X, 
  Instagram, 
  Facebook, 
  Twitter, 
  Mail, 
  Phone, 
  MapPin, 
  Star, 
  Check, 
  ChevronRight, 
  ArrowRight,
  User,
  Calendar,
  Image as ImageIcon,
  MessageSquare,
  Globe
} from 'lucide-react';

// --- Components ---

const Navbar = ({ activePage, setPage }) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { name: 'Home', id: 'home' },
    { name: 'Portfolio', id: 'portfolio' },
    { name: 'Services', id: 'services' },
    { name: 'About', id: 'about' },
    { name: 'Contact', id: 'contact' },
  ];

  return (
    <nav className={`fixed w-full z-50 transition-all duration-300 ${isScrolled ? 'bg-black/90 backdrop-blur-md py-4' : 'bg-transparent py-6'}`}>
      <div className="max-w-7xl mx-auto px-6 flex justify-between items-center">
        <div 
          className="text-2xl font-serif font-bold tracking-tighter text-white cursor-pointer flex items-center gap-2"
          onClick={() => setPage('home')}
        >
          <Camera className="text-amber-500" />
          LUMINA <span className="text-amber-500 font-light">STUDIOS</span>
        </div>

        {/* Desktop Nav */}
        <div className="hidden md:flex space-x-8 items-center">
          {navLinks.map((link) => (
            <button
              key={link.id}
              onClick={() => setPage(link.id)}
              className={`text-sm uppercase tracking-widest transition-colors ${activePage === link.id ? 'text-amber-500' : 'text-gray-300 hover:text-white'}`}
            >
              {link.name}
            </button>
          ))}
          <button 
            onClick={() => setPage('contact')}
            className="bg-amber-600 hover:bg-amber-500 text-white px-6 py-2 rounded-full text-xs uppercase tracking-widest transition-all transform hover:scale-105"
          >
            Book Now
          </button>
        </div>

        {/* Mobile Toggle */}
        <button className="md:hidden text-white" onClick={() => setMobileMenuOpen(!mobileMenuOpen)}>
          {mobileMenuOpen ? <X /> : <Menu />}
        </button>
      </div>

      {/* Mobile Menu */}
      {mobileMenuOpen && (
        <div className="absolute top-0 left-0 w-full h-screen bg-black flex flex-col items-center justify-center space-y-8 z-40 animate-in fade-in zoom-in duration-300">
          <button className="absolute top-6 right-6 text-white" onClick={() => setMobileMenuOpen(false)}><X size={32} /></button>
          {navLinks.map((link) => (
            <button
              key={link.id}
              onClick={() => { setPage(link.id); setMobileMenuOpen(false); }}
              className={`text-2xl uppercase tracking-[0.2em] ${activePage === link.id ? 'text-amber-500' : 'text-white'}`}
            >
              {link.name}
            </button>
          ))}
        </div>
      )}
    </nav>
  );
};

const Footer = ({ setPage }) => (
  <footer className="bg-zinc-950 text-white py-16 px-6 border-t border-zinc-800">
    <div className="max-w-7xl mx-auto grid grid-cols-1 md:grid-cols-4 gap-12">
      <div className="col-span-1 md:col-span-1">
        <div className="text-2xl font-serif font-bold tracking-tighter mb-6">
          LUMINA <span className="text-amber-500 font-light">STUDIOS</span>
        </div>
        <p className="text-gray-400 text-sm leading-relaxed mb-6">
          Capturing the soul of every moment. Providing premium visual storytelling.
        </p>
        <div className="flex gap-4">
          <Instagram className="text-gray-400 hover:text-amber-500 cursor-pointer" size={20} />
          <Facebook className="text-gray-400 hover:text-amber-500 cursor-pointer" size={20} />
        </div>
      </div>
      <div>
        <h4 className="text-lg font-medium mb-6">Quick Links</h4>
        <ul className="space-y-3 text-sm text-gray-400">
          <li><button onClick={() => setPage('portfolio')} className="hover:text-amber-500">Portfolio</button></li>
          <li><button onClick={() => setPage('services')} className="hover:text-amber-500">Services</button></li>
          <li><button onClick={() => setPage('about')} className="hover:text-amber-500">About</button></li>
          <li><button onClick={() => setPage('contact')} className="hover:text-amber-500">Contact</button></li>
        </ul>
      </div>
      <div>
        <h4 className="text-lg font-medium mb-6">Our Services</h4>
        <ul className="space-y-3 text-sm text-gray-400">
          <li>Wedding Cinema</li>
          <li>Editorial Portraits</li>
          <li>Event Coverage</li>
          <li>Product Commercials</li>
        </ul>
      </div>
      <div>
